INSERT INTO comments (_id, comment, images, score, star, publish_date, room_type, fuzzy_room_type, travel_type, comment_len, useful_count, review_count, quality_score, categories, category1, category2, category3) VALUES 
('6802833ee3c98b0941766028', '咁岩有事返内地，顺路去广州玩兼同老婆庆生。今次入住花园酒店三晚，地点方便极近淘金地铁站。 酒店大堂金碧辉煌，好有气派，前台同事特意帮我哋升级左套房，间房好大而且卫生。感谢帮我地check in既前台同事niki, 笑容亲切有礼，态度和蔼。老婆生日 酒店有送生日蛋糕。全个入住体验十分满意。下次黎广州都会再考虑花园酒店', '["https://dimg04.c-ctrip.com/images/02331224x8vq6csey7DFD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02359224x8vq6csf0EE8D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233v224x8vq65r6u1F15_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z224x8vq4abye3801_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-25', '花园大床房', '大床房', '情侣出游', 158, 0, 9, 8, '["前台服务","交通便利性","整体满意度"]'::jsonb, '前台服务', '交通便利性', '整体满意度'),
('6802833ee3c98b0941766029', '座标方便，非常满意', '["https://dimg04.c-ctrip.com/images/0234k224x8yccw4tz6B68_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236q224x8ycdstud0BE7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232b224x8ycbg8fuCD42_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-12-31', '城央绿意大床房', '大床房', '独自旅行', 9, 0, 2, 3, '["交通便利性","整体满意度"]'::jsonb, '交通便利性', '整体满意度', NULL),
('68028349e3c98b094176602a', '酒店位置好，近淘金地铁站位处广州中心点，出行那里都方便，附近有很多美食咖啡店，职员专业有礼，客房干净明亮', '["https://dimg04.c-ctrip.com/images/0234a224x8x9xtoze4273_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235p224x8x9y5lvdC366_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-02', '花园大床房', '大床房', '商务出差', 52, 0, 77, 7, '["交通便利性","周边配套","卫生状况"]'::jsonb, '交通便利性', '周边配套', '卫生状况'),
('68028349e3c98b094176602b', '这次订了红棉升级到粤韵，非常宽敞舒适，十分值得推荐。房间装修还很新净，细节安排很好，浴缸超赞，而且住在花园特别有广东风味，不像其他国际品牌，有现代感但没有地方特色。泳池和健身室都不错，不能错过荔湾亭的点心和瀑布餐厅的自助餐。', '["https://dimg04.c-ctrip.com/images/0235w12000eqzb5ys8E2E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235512000eqzatbbCA02_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230412000eqzb8ik4338_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t12000eqzb008845F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-11', '红棉大床套房', '套房', '家庭亲子', 112, 0, 5, 9, '["房间设施","整体满意度","餐饮设施"]'::jsonb, '房间设施', '整体满意度', '餐饮设施'),
('68028349e3c98b094176602c', '我很喜欢这个地方。它是老式豪华酒店的典范，散发着优雅气息，维护得非常好。房间很漂亮，很有特色，室外场地也很不错。餐厅简直太棒了：Stiller 是我在广州最喜欢的餐厅，铁板烧餐厅很棒，大堂里甚至还有地方可以喝一杯拿铁，还有很棒的糕点可供选择。从红线地铁步行 2 分钟即可到达。', '["https://dimg04.c-ctrip.com/images/0234h12000faep8kaD283_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0235o12000faep4g93D96_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0235k12000faep29nDE61_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2024-08-28', '红棉双床套房', '套房', '商务出差', 138, 0, 16, 9, '["餐饮设施","交通便利性","整体满意度"]'::jsonb, '餐饮设施', '交通便利性', '整体满意度'),
('68028349e3c98b094176602d', '红棉双床房气派不凡, 楼层提供贴心管家服务. 房间整洁没有吸烟的气味. 经平台订了两个房间, 但前台服务员说要自己通知酒店安排同一楼层, 否则要分开分开两个楼层. 等了两小时极力争取下, 方可安排同一楼层.  这方面Trip.com 极需要反映给酒店知道.', '["https://dimg04.c-ctrip.com/images/0234t12000er0iwh02CB9_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2024-07-11', '红棉双床套房', '套房', '家庭亲子', 128, 0, 5, 7, '["前台服务","客房服务","卫生状况"]'::jsonb, '前台服务', '客房服务', '卫生状况'),
('68028349e3c98b094176602e', '房间大且漂亮，非常洁净。酒店员工友善专业。酒店设施很多，遗憾没享用泳池。以五星酒店计，早餐实有空间作出改善。整体入住体验非常好，会再次入住此酒店。', '["https://dimg04.c-ctrip.com/images/0235d12000f2cex991E06_R_150_150_R5_Q70_D.png","https://dimg04.c-ctrip.com/images/0232h12000f2cevpnDDEF_R_150_150_R5_Q70_D.png"]'::jsonb, 5, 5, '2024-08-09', '红棉大床套房', '套房', '独自旅行', 73, 0, 7, 7, '["整体满意度","房间设施","卫生状况"]'::jsonb, '整体满意度', '房间设施', '卫生状况'),
('68028349e3c98b094176602f', '住了一晚，非常愉快。免费升级到 66 型房。', '["https://dimg04.c-ctrip.com/images/02353224x8xe9puh0E6E5_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-11-08', '花园大床房', '大床房', '商务出差', 22, 0, 22, 5, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028349e3c98b0941766030', '我喜欢一切，房间的服务是5分，清洁度一直保持，唯一的问题是接待处总是有人排队，楼下的餐厅营业到22点，然后才到房间。 总的来说，这是一家很棒的酒店。', '["https://dimg04.c-ctrip.com/images/0236y424x8vvtbxjbED66_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231y424x8vvtcj2a77C9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232u424x8vvtbxjc943F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230v424x8vvt9jno689C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-09', '红棉大床套房', '套房', '情侣出游', 74, 0, 2, 6, '["客房服务","卫生状况","前台服务"]'::jsonb, '客房服务', '卫生状况', '前台服务'),
('68028349e3c98b0941766031', '前台人员不太友好，特别是在退房时。酒店房间太吵，价格相对于酒店房间来说确实很高。', '["https://dimg04.c-ctrip.com/images/0235j12000gwisx0z40E9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 2.5, 2, '2024-11-27', '花园双床房', '双床房', '独自旅行', 40, 0, 17, 5, '["前台服务","安静程度","价格合理性"]'::jsonb, '前台服务', '安静程度', '价格合理性'),
('68028349e3c98b0941766032', '总体来说，都可以，就是设施有点旧，服务是可以的，免费帮房间升级。前台小哥哥服务好，点赞，最值得看得是酒店的博物馆。', '["https://dimg04.c-ctrip.com/images/02336224x8w3zmtpr6A8E_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-08-29', '花园双床房', '双床房', '家庭亲子', 57, 0, 4, 6, '["房间设施","前台服务","整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度'),
('68028349e3c98b0941766033', '房间布局和设计不太人性化。工作人员很有礼貌，英语熟练', '["https://dimg04.c-ctrip.com/images/0236j224x8x2g6ccz5F33_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02370224x8x2i8pcnA8E4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02343224x8x2hcgyq9FBE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-10-21', '花园大床房', '大床房', '家庭亲子', 26, 0, 21, 5, '["房间设施","前台服务"]'::jsonb, '房间设施', '前台服务', NULL),
('68028353e3c98b0941766034', '非常喜欢在这里住了两个星期！工作人员非常友好和乐于助人，清洁工总是那么健谈和有礼貌，每天都会把我的房间打扫得那么干净。我一定会再来这家酒店住，也会推荐给我的家人和朋友！', '["https://dimg04.c-ctrip.com/images/0236812000eszop9fE5C2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0237212000eszmshb167D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230z12000eszogsiBD98_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231212000eszjeh84B22_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236712000eszozf1BA0A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-17', '花园大床房', '大床房', '商务出差', 84, 0, 6, 8, '["客房服务","整体满意度","卫生状况"]'::jsonb, '客房服务', '整体满意度', '卫生状况'),
('68028353e3c98b0941766035', '本人和父母于2024/06 租住两相连房间 住两日
以下系本人所见所闻
1 浴缸设计独特 位置新颖 但漏水
2 房景若对游客就略微扣分 酒店此处外观需要尽快现代化
3 楼层走?设计很好 和父母拍了多张留念 如果有花香味道就更好
4 重点：房咭住了两天 坏了好多次 希望酒店方不会为其他客户带来不方便 我被安排到其他房间等待维修时 听到此维修人员态度不太好 
5 房间的茶味道确实不太合适 非一般人可以适应
6 图片中的圆镜 接触不好 

本人的祖辈华侨70年代于广州开始生活 眼见国家级酒店兴建 有幸还有气力住两日 百感交集 时代变迁 略低于水准 希望有朝一日重临酒店', '["https://dimg04.c-ctrip.com/images/0230k224x8weq1lsm3366_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02308224x8weph2kj92BE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235y224x8weq0z8m2F55_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233b224x8wepisg7B5C7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231x224x8wepvbtzB3F8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231z224x8weov5ys97D0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g224x8wepintc6015_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02344224x8wep76t2AE5D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233t224x8wepq3daE974_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-09-16', '花园大床房', '大床房', '独自旅行', 284, 0, 1, 7, '["房间设施","前台服务","整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度'),
('68028353e3c98b0941766036', '广州传统老牌五星洒店，?位置非常优越，?酒店配套设施也齐全。?宽敞的接待大厅，?算系国内行业中可能最大的。?客房服务也相当不俗。???这次带着怀旧情怀之意，?为工作便利刻意选择了环市东路商圈的花园酒店?一晚。????大堂接待亲切有礼，?客房部员工也尽职服务服务！?本想在顶楼旋转餐厅与客户晚膳＇?只可惜已关闭四年了。?唯有选择了酒店的日本料理餐厅。?环境尚算可以，?食物质素尚可。??结帐后，??餐厅职员第二天上午，在我催促下才给予我发票????这是一间正常餐厅不应该出现的错误行为。?系这次商务唯一不愉快的地方。', '["https://dimg04.c-ctrip.com/images/0236j224x8v2hht9t8617_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230y224x8v2i5ifz3800_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230j224x8v2ijvaa5C18_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2024-05-30', '花园双床房', '双床房', '商务出差', 257, 0, 6, 8, '["前台服务","客房服务","周边配套"]'::jsonb, '前台服务', '客房服务', '周边配套'),
('68028353e3c98b0941766037', '第一次住广州花园酒店，日式的房间很好，性价比超级高，关键是服务也超级好，行政酒廊的Carrie、Aimee、Mignom的服务很热情，回家的感觉,下次来首选花园酒店??', '["https://dimg04.c-ctrip.com/images/0236r12000eh5lkz734EB_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000eh5jk4u0899_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231i12000eh5h2e74664_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230712000eh5mhozD594_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-14', '花园大床房', '大床房', '朋友出游', 84, 0, 2, 7, '["整体满意度","性价比","前台服务"]'::jsonb, '整体满意度', '性价比', '前台服务'),
('68028353e3c98b0941766038', '很棒的酒店，非常干净，位置非常好，靠近地铁站，附近还有洋餐厅，靠近市中心。环境非常舒适，前台服务态度非常好，特别是年轻的才女Niki。她真的很受人尊敬，非常专业。', '["https://dimg04.c-ctrip.com/images/0235g12000eazfai603C2_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-04', '红棉大床套房', '套房', '商务出差', 81, 0, 6, 9, '["整体满意度","交通便利性","前台服务"]'::jsonb, '整体满意度', '交通便利性', '前台服务'),
('68028353e3c98b0941766039', '非常好的酒店，早餐很棒！', '["https://dimg04.c-ctrip.com/images/0230q224x8xkl3sgj8F92_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-11-18', '花园双床房', '双床房', '朋友出游', 12, 0, 15, 3, '["餐饮设施","整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL),
('68028353e3c98b094176603a', '房间宽阔，整洁，舒适，用品齐全，工作人员热情款待，由入住开始，有专人招呼，十分体贴，直接带入房间。还介绍洒店内设施，我们入住3天，享用行政礼遇，丰富自助早餐，下午茶，欢乐时光。出品唔错，还品尝二间米其林歺厅，荔湾亭，桃园馆，吃到美味佳肴，下次一定会再来！', '["https://dimg04.c-ctrip.com/images/0235512000dhmf82n5876_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230o12000dhmfb2v42C0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236j12000dhmfl9o1E32_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236c12000dhmg3shCD9C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236e12000dhmfx6448E5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233012000dhmg81q3A4B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230712000dhmg25w0153_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235012000dhmg6q193E0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230q12000dhmf82t765C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-24', '粤韵双床套房', '套房', '独自旅行', 127, 0, 1, 9, '["整体满意度","餐饮设施","前台服务"]'::jsonb, '整体满意度', '餐饮设施', '前台服务'),
('68028353e3c98b094176603b', '不愧是老牌的五星酒店，服务和硬件都无可挑剔。适逢广交会，人比较多，早餐也开放了三个餐厅，最起码我就不用等。早上还在我住的楼层电梯口那边准备好?啡，给那些睡过头赶出门的住客提供了贴心服务。这次房间被免费升级了，多了个客厅可以用。房间洗漱用品都很全，连漱口水也有。贵是贵了，但是物有所值。', '["https://dimg04.c-ctrip.com/images/0232312000dozai7b1029_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232k12000doz1q5t5DFA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234n12000dozd3x05C74_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231512000dp0049oE3E2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232q12000doz8leoFBF0_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-16', '花园大床房', '大床房', '商务出差', 142, 0, 123, 9, '["整体满意度","前台服务","性价比"]'::jsonb, '整体满意度', '前台服务', '性价比'),
('68028353e3c98b094176603c', '酒店环境服务周边商场交通配套都很好，自助早餐款式选择味道也不错，用餐餐厅瀑布环境才是重点。房间洗手盘边位长霉菌需留意。', '["https://dimg04.c-ctrip.com/images/0230h224x8v9m3vu65D1E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02364224x8v9lmw3pF350_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-06-12', '花园双床房', '双床房', '朋友出游', 59, 0, 11, 7, '["周边配套","餐饮设施","卫生状况"]'::jsonb, '周边配套', '餐饮设施', '卫生状况'),
('68028353e3c98b094176603d', '地方清洁，房间舒适，虽然住在电梯旁，但也非常安静。
房内有咖啡机，咖啡不错。
大堂漂亮，有很多员工。
当天好像有conference, 外国人比较多，所以他们处理有点缓慢，但最后也', '["https://dimg04.c-ctrip.com/images/02371224x8ukx4lyzB737_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232r224x8ukxeqct8E96_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02356224x8ukwsn9h1AEF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-22', '花园大床房', '大床房', '家庭亲子', 90, 0, 8, 7, '["卫生状况","安静程度","房间设施"]'::jsonb, '卫生状况', '安静程度', '房间设施'),
('6802835fe3c98b094176603e', '酒店环境一流，干净舒服。多次入住，保持白金水准。孩子们很开心，在博物馆也学到很多知识，下次来广州还会选择花园酒店。', '["https://dimg04.c-ctrip.com/images/0234t224x8vb9m02jB404_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231u224x8vb9m02k20C7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236n224x8vb9zuib9E48_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02313224x8vbb24hg981F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234y224x8vbb24hh41BF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230x224x8vb9pxql2D42_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-15', '羊羊得意主题大床房', '主题房', '家庭亲子', 57, 0, 20, 7, '["整体满意度","卫生状况"]'::jsonb, '整体满意度', '卫生状况', NULL),
('6802835fe3c98b094176603f', '古香古色，宾至如归。。超好。。', '["https://dimg04.c-ctrip.com/images/0230h224x8vv8lucdCF6F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230u224x8vv8k53n0846_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02361224x8vv8o15t2937_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-08-07', '红棉双床套房', '套房', '家庭亲子', 15, 0, 3, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('6802835fe3c98b0941766040', '服务：优质服务酒店的最大特色！果然是白金五星酒店！

设施：拥有多间米其林特色餐厅，每一间都值得一试，当然，价格也不便宜哈??', '["https://dimg04.c-ctrip.com/images/0235p12000du0ju710068_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236g12000du13r5r2215_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233s12000du0rcjw715A_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236l12000du0j3rq3A2A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-04-30', '花园双床房', '双床房', '家庭亲子', 63, 0, 13, 6, '["餐饮设施","整体满意度"]'::jsonb, '餐饮设施', '整体满意度', NULL),
('6802835fe3c98b0941766041', '一间老牌国宾馆，名气大，设施好，近地铁，附近没有什么食肆，酒店内的人造瀑布非常漂亮，拍照位甚多，我们订的套房很舒适，面积大，床上和洗澡用品亦好，设备齐全，唯一就是 check in 取房排队时间较长，等了差不多 45分钟，但大堂又没有什么梳化坐椅给客人休息，这点可以改善一下。', '["https://dimg04.c-ctrip.com/images/0236w224x8ufarajnA67C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234y224x8ufb1fa70066_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233t224x8ufas1spC950_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02311224x8ufa19pq978B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236k224x8ufanqw9F859_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230k224x8ufb1v1lC3A9_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-04-05', '红棉大床套房', '套房', '家庭亲子', 138, 0, 30, 8, '["房间设施","退房/入住效率","交通便利性"]'::jsonb, '房间设施', '退房/入住效率', '交通便利性'),
('6802835fe3c98b0941766042', '带孩子全家出游，定了红棉双床房，给12岁儿童免费加床。一房一厅非常舒适，孩子很喜欢，客房服务周到，忘记带转换插座和UBS线，酒店都能提供！', '["https://dimg04.c-ctrip.com/images/0236h224x8ue5xcpuDFBA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233z224x8ue4fi4eCD49_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-04-02', '红棉双床套房', '套房', '家庭亲子', 69, 0, 1, 7, '["客房服务","房间设施","整体满意度"]'::jsonb, '客房服务', '房间设施', '整体满意度'),
('6802835fe3c98b0941766043', '老广的No.1

一入门的确被红楼梦的金碧辉煌惊艳到了
迎宾的小姐姐们也人手充配企待客有方

新年的缘故特意订了比较高小小等级的房型

下午三时到达也排了半小时队才能登记
被告知房间未收拾好
问了我们联系电话说是准备好便会打给我们
再问了迎宾的小姐姐
被告知晚上回来肯定有房的
令人好气又好笑
结果到我们晚上10点多回酒店也未收到电话

房间虽然装修过
也算是对得起国内五星酒店的标准的
和天河那边的新五星是无法相比的了

第二天回来，又另一件趣事发生
洗手间和洗手间垃圾桶没有清理
打电话去问为什么没有清理
竟然说我们开了「请勿打扰」
第一我们肯定是开了「请打扫」
第二如果我们开了请勿打扰
那贵酒店收拾了我们的床铺啊，客厅的垃圾桶啊，更换了毛巾啊…那不是前后矛盾？
于是他们们又急急派了人来处理

反正吧
如果会来广州住不同的酒店体验一下
这老广的白金五星是可以试一下的
那种80/90年代的繁花味道还在
如果不是常来广州
又不希望有太傻的服务
那住过去天河的新五星吧', '["https://dimg04.c-ctrip.com/images/0236w224x8u22vi1n3DEE_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02359224x8u22s0ec12A4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234w224x8u236yolDBB7_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3, 3, '2024-02-17', '红棉大床套房', '套房', '家庭亲子', 436, 0, 5, 9, '["前台服务","客房服务","整体满意度"]'::jsonb, '前台服务', '客房服务', '整体满意度'),
('6802835fe3c98b0941766044', '酒店位置邻近地铁站，非常方便。酒店房间非常整洁，每天除了基本清洁和更换毛巾，更每日提供新的拖鞋，非常贴心。
此外，位于30楼的餐厅食物质素良好，除了早餐，更有行政下午茶及欢乐时光可供享用。
因我于春节期间入住，酒店亦提供不同活动，虽然我没有时间参与，但亦突显酒店的用心。', '["https://dimg04.c-ctrip.com/images/02368224x8u1jcimwB83C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234b224x8u1jccyf521D_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236s224x8u1jccygAACF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02365224x8u1j5t3sD1A8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02335224x8u1ix9kjF3B8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-15', '花园大床房', '大床房', '家庭亲子', 135, 0, 5, 9, '["交通便利性","卫生状况","餐饮设施"]'::jsonb, '交通便利性', '卫生状况', '餐饮设施'),
('6802835fe3c98b0941766045', '很好..简单', '["https://dimg04.c-ctrip.com/images/0232v224x8vm9q39j8403_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-07-15', '花园大床房', '大床房', '商务出差', 6, 0, 1, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('6802835fe3c98b0941766046', '免费升级到新房型，非常好的体验。花园厚重的历史从大门就能感受到是妥妥的广州天花板之一。员工的服务态度也是世界五星级的。宝宝很喜欢门口的大羊羊和钢琴上的小羊。唯一遗憾是周日入住没赶上酒店博物馆，周一刚好不开', '["https://dimg04.c-ctrip.com/images/02338224x8u5btb9iDF0F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-01', '红棉大床套房', '套房', '家庭亲子', 102, 0, 36, 9, '["整体满意度","前台服务","公共设施"]'::jsonb, '整体满意度', '前台服务', '公共设施'),
('6802835fe3c98b0941766047', '环境好，房间舒服干净', '["https://dimg04.c-ctrip.com/images/0236f224x8v8o8w6jEC7D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-06-10', '花园大床房', '大床房', '家庭亲子', 10, 0, 6, 4, '["卫生状况","整体满意度"]'::jsonb, '卫生状况', '整体满意度', NULL),
('6802836ae3c98b0941766048', '房间休息好舒服，好干净，是一间拥有好好硬件的酒店，服务员好有礼貌，体验到酒店人材训练有素。
房间不好方面是冲凉时如果是用淋浴会令外面地下湿晒，隔门及淋浴头需要适当地维修。
酒店瀑布餐厅的晚餐自助餐只能说是求精不求多，只是食物都不多，某些受欢迎食物长期没。另外自助早餐真心是失望，食物款式少，而且仲要唔好食。(?晚餐可以试下，早餐就真的不用试)', '["https://dimg04.c-ctrip.com/images/02357224x8tmzhx4s1B80_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232a224x8tmzsb9v8AC7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/02330224x8tmzrvkuF3F6_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236b224x8tmzws2yA340_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230m224x8tmzws2z66D8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230w224x8tmzrwh8880F_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-12-27', '花园双床房', '双床房', '家庭亲子', 171, 2, 9, 8, '["房间设施","卫生状况","前台服务"]'::jsonb, '房间设施', '卫生状况', '前台服务'),
('6802836ae3c98b0941766049', '这家酒店太棒了', '["https://dimg04.c-ctrip.com/images/0232312000dutltvs2DFD_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2024-05-02', '红棉大床套房', '套房', '商务出差', 7, 1, 10, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('6802836ae3c98b094176604a', '一间非常之好嘅酒店、酒店花园非常之优美、服务到位员工非常有礼貌…. 重有惊喜因入住其间是我本人生日、酒店送了一个生日蛋糕??！
为一不满意地方是瀑布餐厅的自助晚餐…食物种类小，选择不多质素非常一般、而且收费和食物质素不成正比！￥300多人民一位食家常小菜自助晚餐有点过份??', '["https://dimg04.c-ctrip.com/images/0233n2234cnp519yoF6BD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232j2234cnp51hogB426_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230k2234cnp51pe84145_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232g2215ggyswmi8A36E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023042224wkbyzldsD1F9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230t2215ggysx1xtA577_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023352215ggysx9nk6448_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234v2224wkbz08j4DCDF_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023602234cnp537eo9E34_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-09-25', '花园双床房', '双床房', '家庭亲子', 137, 0, 3, 7, '["餐饮设施","整体满意度","前台服务"]'::jsonb, '餐饮设施', '整体满意度', '前台服务'),
('6802836ae3c98b094176604b', '客房环境，酒店设施，员工服务无一不是五星级水准，简直无可挑剔。花园酒店，酒店为次，实为花园，闻名不如见面。三十年如一日保持水准实属难得。', '["https://dimg04.c-ctrip.com/images/0232u12000ctxgxti04B9_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235m12000ctxebpu6166_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236412000ctx8qja5DA7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234812000ctxg65098B1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235012000ctxga91E5EE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-30', '花园大床房', '大床房', '独自旅行', 68, 0, 2, 8, '["整体满意度","公共设施","前台服务"]'::jsonb, '整体满意度', '公共设施', '前台服务'),
('6802836ae3c98b094176604c', '酒店就在地铁站旁边，出行逛街都很方便，办理入住还有送鲜花??，心情一下美好了，另外内部设计设计很好看，就算在酒店里逛逛都能发现新亮点。房间里总体舒适度也够，只因酒店附近有工程在修建，早上8点到晚上10点在室内还是有点声音，就这一点会比较尴尬。入住的话，可以跟前台工作人员咨询一下！', '["https://dimg04.c-ctrip.com/images/023202224x3r1h8zlCA6E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232g2224x3r1h8zo4B42_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023692234d747k7v4DE67_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-11-13', '花园双床房', '双床房', '朋友出游', 140, 0, 5, 8, '["交通便利性","前台服务","安静程度"]'::jsonb, '交通便利性', '前台服务', '安静程度'),
('6802836ae3c98b094176604d', '?带着母亲，?怀缅一下环市东路
? 80年代尾至90年代的暑假
经常在这里出门
花园酒店是我们的回忆之一
?在淘金地铁站口，对面友谊百货， ?很有情怀
??房间也很干净舒适！?
?地下的花园很漂亮，?我和妈妈住得很开心', '["https://dimg04.c-ctrip.com/images/023662234d775jl9d92F0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0236i2215h0gteankD8E4_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023182224x3tzh9j4E94F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234a2215h0gteq35C70B_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230o2234d775kg4hCC8E_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023572234d775knu8B007_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.7, 4, '2023-11-13', '花园双床房', '双床房', '家庭亲子', 109, 0, 10, 7, '["整体满意度","交通便利性","卫生状况"]'::jsonb, '整体满意度', '交通便利性', '卫生状况'),
('6802836ae3c98b094176604e', '服务周到，热情欢迎，非常好的体验', '["https://dimg04.c-ctrip.com/images/0231r224x8uczrphg98D4_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-03-29', '城央绿意双床房', '双床房', '家庭亲子', 16, 0, 3, 3, '["前台服务","整体满意度"]'::jsonb, '前台服务', '整体满意度', NULL),
('6802836ae3c98b094176604f', '酒店房间明显陈旧，希望有机会可以翻新,但地理位置非常好，一出门就有地铁站交通方便,餐厅服务人员很有礼貌，服务周到,桃园厅，食品质量很好，不愧为米之莲餐厅??', '["https://dimg04.c-ctrip.com/images/0230e2215ha1ddahsEA40_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235e2224xdejg1nk9B17_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234d2224xdejg1nn9185_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023562224xdejg1nm5DBD_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233d2224xdejg1nl5DB7_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023282215ha1ddahvA6D8_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-12-07', '花园大床房', '大床房', '情侣出游', 78, 0, 3, 7, '["交通便利性","餐饮设施","房间设施"]'::jsonb, '交通便利性', '餐饮设施', '房间设施'),
('6802836ae3c98b0941766050', '解锁中国改革开放的两间标志性的酒店——广州花园酒店。完全没法想像是一家38年的酒店，酒店房好新好舒服，东西一尘不染，大大的好评。', '["https://dimg04.c-ctrip.com/images/0233u224x8tsukd5c9797_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234o224x8tsus81gC424_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233o224x8tsustwa6E8C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-01-19', '红棉大床套房', '套房', '情侣出游', 64, 0, 94, 6, '["整体满意度","卫生状况","房间设施"]'::jsonb, '整体满意度', '卫生状况', '房间设施'),
('6802836ae3c98b0941766051', '广州老牌五星大酒店，地点近便，地铁站上盖步行数分钟路程，堂皇华丽金碧辉煌的大堂接待处已是亮点，正值中秋??等待check in时还有接待员亲切地祝福中秋节快乐还送赠了一盒月饼??高档次且大气，房间算大，床褥枕头舒适，出行近便，赞????', '["https://dimg04.c-ctrip.com/images/0231t224x8tjg55xl0843_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235u224x8tjg2mus7E02_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235r224x8tjg0d7k9580_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233j224x8tjg1jo2BB3C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235f224x8tjg0oxvDAB2_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231p224x8tjg0bgnF655_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232o224x8tjg58tq4A50_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-12-10', '城央绿意大床房', '大床房', '朋友出游', 118, 0, 21, 8, '["交通便利性","前台服务","整体满意度"]'::jsonb, '交通便利性', '前台服务', '整体满意度'),
('68028374e3c98b0941766052', '虽然对于地下停车场跟酒店本身没有连通有点不满意，但考虑到酒店的历史，还能安慰一下自己。
直到Check in时，遇到非常友善亲切的Gillian，才让我发现，原来这是一间以人为本的酒店。也正式开启了愉快的一天。
因为老人家比较晚到，也很感谢她能帮我解决很多小问题，很多我还没设想到的，都想到了，非常棒！鲜花也让太座和女鹅非常惊喜！
在房间走道遇到任何的工作人员尽管他/她正在忙，也会友善的问候一句您好。
博物馆也是详细记载了酒店的历史，非常值得一观。
结束疲劳的一天，回到房间也被点心吓一跳，真的很轻易的俘虏了女鹅的小心心。

其实住遍了国际五星难免对于服务这点是特别有感，但花园酒店，有让我觉得，一点都不输。', '["https://dimg04.c-ctrip.com/images/0232y12000c6fm5n03800_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231012000c6ffyqa02EA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0235g12000c6fp8bw5DD0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0231712000c6fchhgCDCF_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-18', '花园双床房', '双床房', '家庭亲子', 305, 0, 38, 9, '["前台服务","整体满意度","客房服务"]'::jsonb, '前台服务', '整体满意度', '客房服务'),
('68028374e3c98b0941766053', '大堂漂亮宏伟，后面不单有瀑布花园，顶层还有个博物馆，而且店内各式餐厅都有。坏天气都不用出大门了，内里都可消缒几天不闷。
设施：只差没泳池。
卫生：很干净，有自动空气清新机。
环境：一流。
服务：也非常好。', '["https://dimg04.c-ctrip.com/images/0235p12000c6ntiq9B975_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232912000c6nq4k07A52_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230w12000c6nvmw343DE_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-19', '花园大床房', '大床房', '情侣出游', 102, 0, 33, 8, '["公共设施","餐饮设施","卫生状况"]'::jsonb, '公共设施', '餐饮设施', '卫生状况'),
('68028374e3c98b0941766054', '我真的很高兴住在花园酒店，太棒了，24 小时里每天都有灿烂的笑容，新鲜的鲜花，美丽的花园，有瀑布和漂亮的鱼，还有非常非常有礼貌的人员，以及完美的款待。
我爱岭花园??????????', '["https://dimg04.c-ctrip.com/images/0234x12000ca5ah25BD88_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2023-09-29', '花园双床房', '双床房', '商务出差', 91, 0, 2, 7, '["整体满意度","前台服务","景观/朝向"]'::jsonb, '整体满意度', '前台服务', '景观/朝向'),
('68028374e3c98b0941766055', '一切都太美好了??', '["https://dimg04.c-ctrip.com/images/0236x12000d9tzylu7B73_R_150_150_R5_Q70_D.jpg"]'::jsonb, 5, 5, '2024-02-23', '花园大床房', '大床房', '商务出差', 9, 0, 1, 2, '["整体满意度"]'::jsonb, '整体满意度', NULL, NULL),
('68028374e3c98b0941766056', '我们都很满意房间，又大又整溸，还是刚刚装修完，唯一可惜就是泳池正在装修停用。在此特别感谢员工 Aerial 很有礼貌及有耐性解答我的问题，最后还帮我将房间升级了，令我有宾至如归的感觉，下次再到广州，一定再会再入住花园酒店?', '["https://dimg04.c-ctrip.com/images/0233x12000c3sgbzw41F1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0230s12000c3sn6hhF127_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232b12000c3sr265730C_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233a12000c3snoi0E33C_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4, 4, '2023-09-10', '红棉大床套房', '套房', '家庭亲子', 111, 0, 8, 8, '["房间设施","前台服务","整体满意度"]'::jsonb, '房间设施', '前台服务', '整体满意度'),
('68028374e3c98b0941766057', '服务态度??交通方便??', '["https://dimg04.c-ctrip.com/images/02368224x8ucvhzgyD696_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.2, 4, '2024-03-29', '花园大床房', '大床房', '家庭亲子', 12, 0, 23, 3, '["前台服务","交通便利性"]'::jsonb, '前台服务', '交通便利性', NULL),
('68028374e3c98b0941766058', '职员专业友善，环境十分洁净??
只是附近有很多任务程，开车去不太容易找', '["https://dimg04.c-ctrip.com/images/0234e2215h82fr7gwF547_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233g2224xbfltympC99F_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023582234desrwxi83C37_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023262215h82frmwgC3F0_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232c2234desrxknk7FB3_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023672234desrxknl580A_R_150_150_R5_Q70_D.jpg"]'::jsonb, 4.5, 4, '2023-12-02', '花园大床房', '大床房', '情侣出游', 35, 0, 5, 5, '["前台服务","卫生状况","交通便利性"]'::jsonb, '前台服务', '卫生状况', '交通便利性'),
('68028374e3c98b0941766059', '花园酒店好唔掂！无下次！网上说她好的人绝对是日行一善。酒店大堂气势磅礴，叻得下人。但上到去房间，**一样，装修和设施保持在30年前水平，一点也没有改变。图1，大厦外墙石屎剥落。图2，浴帘霉菌茁壮。图3，墙纸磨到花碌碌。其他图可见，容容烂烂的一间"五星酒店"。一般来说，每年七八月乃旅游旺季，修缉泳池要等冬天才弄，这是常识吧？花园酒店实在烂得要紧，泳池等不及冬天，现在已经停用了。其陈旧程度可见一斑。', '["https://dimg04.c-ctrip.com/images/0231m2224w4k2a2shCEF1_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0234p2215g16w7jch3ED5_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0233h2234c7x8d1o1F356_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023012224w4k2a2si82C8_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/0232w2234c7x8d1o09EDA_R_150_150_R5_Q70_D.jpg","https://dimg04.c-ctrip.com/images/023312215g16w7jciB87D_R_150_150_R5_Q70_D.jpg"]'::jsonb, 3, 3, '2023-08-16', '红棉双床套房', '套房', '家庭亲子', 199, 1, 6, 9, '["房间设施","公共设施","卫生状况"]'::jsonb, '房间设施', '公共设施', '卫生状况')
